using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
            // Preserve the old name so existing 500K documents remain readable,
            // and raw SQL queries that reference c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the id format from "EntityType|KeyValue" to just "KeyValue".
            // Preserve the old format so existing documents can still be found by key.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonPropertyName("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

/// <summary>
/// Reproduces the EF Core 8 Cosmos id format: "EntityTypeName|KeyValue"
/// so that existing documents written by EF Core 8 remain accessible.
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var key = entry.Property("Id").CurrentValue;
        return $"{entry.Metadata.ShortName()}|{key}";
    }
}

