using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
            // Preserve the old name so existing 500K documents remain readable,
            // and raw SQL queries that reference c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the synthesized id format from "EntityType|Key" to just "Key".
            // We map the explicit CosmosId property to the JSON "id" field, preserving the
            // old "Product|<n>" format so existing documents remain accessible.
            entity.HasKey(p => p.CosmosId);
            entity.Property(p => p.CosmosId).ToJsonPropertyName("id");
        });
    }
}

class Product
{
    /// <summary>
    /// Cosmos JSON "id" — existing documents use format "Product|{n}".
    /// New inserts must continue this format: CosmosId = $"Product|{n}".
    /// </summary>
    public string CosmosId { get; set; } = null!;
    public int Id { get; set; }
    public string Sku { get; set; } = null!;
}

